I’d implement it like this in TypeScript:

```ts
type RetryOptions = {
  retries?: number;
  baseDelayMs?: number;
  maxDelayMs?: number;
  timeoutMs?: number;
  shouldRetry?: (error: unknown, attempt: number) => boolean;
};

const sleep = (ms: number, signal?: AbortSignal) =>
  new Promise<void>((resolve, reject) => {
    const timer = setTimeout(resolve, ms);

    signal?.addEventListener(
      "abort",
      () => {
        clearTimeout(timer);
        reject(signal.reason ?? new Error("Operation aborted"));
      },
      { once: true },
    );
  });

export async function retryNetworkCall<T>(
  call: (signal: AbortSignal) => Promise<T>,
  options: RetryOptions = {},
): Promise<T> {
  const {
    retries = 3,
    baseDelayMs = 250,
    maxDelayMs = 5_000,
    timeoutMs = 10_000,
    shouldRetry = defaultShouldRetry,
  } = options;

  let lastError: unknown;

  for (let attempt = 0; attempt <= retries; attempt++) {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(new Error("Request timed out")), timeoutMs);

    try {
      return await call(controller.signal);
    } catch (error) {
      lastError = error;

      if (attempt === retries || !shouldRetry(error, attempt)) {
        throw error;
      }

      const exponentialDelay = Math.min(baseDelayMs * 2 ** attempt, maxDelayMs);
      const jitter = Math.floor(Math.random() * exponentialDelay * 0.25);

      await sleep(exponentialDelay + jitter);
    } finally {
      clearTimeout(timeout);
    }
  }

  throw lastError;
}

function defaultShouldRetry(error: unknown): boolean {
  if (error instanceof Error && error.message === "Request timed out") {
    return true;
  }

  const maybeStatus = (error as { status?: number })?.status;

  return (
    maybeStatus === 408 ||
    maybeStatus === 429 ||
    maybeStatus === 500 ||
    maybeStatus === 502 ||
    maybeStatus === 503 ||
    maybeStatus === 504
  );
}
```

Example usage:

```ts
const result = await retryNetworkCall(async (signal) => {
  const response = await fetch("https://api.example.com/data", { signal });

  if (!response.ok) {
    throw { status: response.status, message: response.statusText };
  }

  return response.json();
});
```

