To confirm it works, I would test these cases:

```ts
import { describe, expect, it, vi } from "vitest";
import { retryNetworkCall } from "./retryNetworkCall";

describe("retryNetworkCall", () => {
  it("returns success on first attempt", async () => {
    const fn = vi.fn().mockResolvedValue("ok");

    await expect(retryNetworkCall(fn)).resolves.toBe("ok");
    expect(fn).toHaveBeenCalledTimes(1);
  });

  it("retries after failures and eventually succeeds", async () => {
    const fn = vi
      .fn()
      .mockRejectedValueOnce(new Error("temporary"))
      .mockRejectedValueOnce(new Error("temporary"))
      .mockResolvedValue("ok");

    await expect(
      retryNetworkCall(fn, { baseDelayMs: 1 })
    ).resolves.toBe("ok");

    expect(fn).toHaveBeenCalledTimes(3);
  });

  it("throws after retry limit", async () => {
    const fn = vi.fn().mockRejectedValue(new Error("down"));

    await expect(
      retryNetworkCall(fn, { retries: 2, baseDelayMs: 1 })
    ).rejects.toThrow("down");

    expect(fn).toHaveBeenCalledTimes(3);
  });

  it("does not retry when shouldRetry returns false", async () => {
    const fn = vi.fn().mockRejectedValue(new Error("bad request"));

    await expect(
      retryNetworkCall(fn, {
        shouldRetry: () => false,
      })
    ).rejects.toThrow("bad request");

    expect(fn).toHaveBeenCalledTimes(1);
  });
});
```

